import{_ as l,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"快速上手：安裝設定啟動 Gateway 並傳送第一條訊息與了解 DM 配對保護 | Clawdbot 教學","description":"本章節引導你完成 Clawdbot 的首次使用，包括安裝、設定、啟動 Gateway、傳送第一條訊息以及了解 DM 配對保護機制。","frontmatter":{"title":"快速上手：安裝設定啟動 Gateway 並傳送第一條訊息與了解 DM 配對保護 | Clawdbot 教學","sidebarTitle":"從零開始使用","subtitle":"快速上手：從安裝到第一條訊息","description":"本章節引導你完成 Clawdbot 的首次使用，包括安裝、設定、啟動 Gateway、傳送第一條訊息以及了解 DM 配對保護機制。","tags":["入門","快速開始"],"prerequisite":[],"order":10},"headers":[],"relativePath":"zh-tw/moltbot/moltbot/start/index.md","filePath":"zh-tw/moltbot/moltbot/start/index.md"}'),e={name:"zh-tw/moltbot/moltbot/start/index.md"};function r(n,a,o,p,h,g){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="快速上手-從安裝到第一條訊息" tabindex="-1">快速上手：從安裝到第一條訊息 <a class="header-anchor" href="#快速上手-從安裝到第一條訊息" aria-label="Permalink to &quot;快速上手：從安裝到第一條訊息&quot;">​</a></h1><p>歡迎使用 Clawdbot！本章節將引導你完成從零開始使用 Clawdbot 的完整流程。無論你是想快速體驗 AI 助手，還是深入了解設定選項，這裡都有對應的教學。</p><hr><h2 id="章節概述" tabindex="-1">章節概述 <a class="header-anchor" href="#章節概述" aria-label="Permalink to &quot;章節概述&quot;">​</a></h2><p>本章節包含 5 個教學，覆蓋了 Clawdbot 的完整上手流程：從安裝軟體、設定 AI 模型和通訊頻道，到啟動 Gateway 背景程序、傳送第一條訊息，最後了解預設的安全保護機制。完成本章節後，你將擁有一個可以正常使用的個人 AI 助手。</p><hr><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><p>我們推薦按照以下順序學習這些教學：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[getting-started&lt;br&gt;快速開始] --&gt; B[onboarding-wizard&lt;br&gt;引導式設定]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[gateway-startup&lt;br&gt;啟動 Gateway]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[first-message&lt;br&gt;傳送第一條訊息]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[pairing-approval&lt;br&gt;DM 配對與存取控制]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#3b82f6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#10b981,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#f59e0b,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#8b5cf6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#ef4444,color:#fff</span></span></code></pre></div><p><strong>學習順序說明</strong>：</p><ol><li><strong>快速開始</strong>（必須）：完成基礎安裝和設定，這是所有後續學習的前提</li><li><strong>引導式設定</strong>（推薦）：深入了解引導的各個選項，適合想要精細設定的使用者</li><li><strong>啟動 Gateway</strong>（必須）：了解如何啟動和管理 Gateway 背景程序</li><li><strong>傳送第一條訊息</strong>（必須）：驗證設定是否正確，開始使用 AI 助手</li><li><strong>DM 配對與存取控制</strong>（推薦）：了解預設的安全機制，保護你的 AI 助手</li></ol><div class="tip custom-block"><p class="custom-block-title">快速通道</p><p>如果你只想快速體驗，可以只學習「快速開始」和「啟動 Gateway」兩個教學，然後直接傳送訊息。其他教學可以後續按需學習。</p></div><hr><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>在學習本章節之前，請確保：</p><ul><li><strong>Node.js</strong>：≥ 22.12.0（使用 <code>node -v</code> 檢查）</li><li><strong>作業系統</strong>：macOS / Linux / Windows (WSL2)</li><li><strong>套件管理員</strong>：npm / pnpm / bun</li><li><strong>AI 模型帳戶</strong>（推薦）： <ul><li>Anthropic Claude 帳戶（Pro/Max 訂閱），支援 OAuth 流程</li><li>或準備好 OpenAI / DeepSeek / OpenRouter 等提供商的 API Key</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Windows 使用者請注意</p><p>Windows 上強烈推薦使用 <strong>WSL2</strong>，因為：</p><ul><li>許多頻道依賴本機二進位檔案</li><li>背景程序（launchd/systemd）在 Windows 上無法使用</li></ul></div><hr><h2 id="子頁面導覽" tabindex="-1">子頁面導覽 <a class="header-anchor" href="#子頁面導覽" aria-label="Permalink to &quot;子頁面導覽&quot;">​</a></h2><h3 id="_1-快速開始-⭐-核心教學" tabindex="-1"><a href="./getting-started/">1. 快速開始</a> ⭐ 核心教學 <a class="header-anchor" href="#_1-快速開始-⭐-核心教學" aria-label="Permalink to &quot;[1. 快速開始](./getting-started/) ⭐ 核心教學&quot;">​</a></h3><p><strong>學完你能做什麼</strong>：</p><ul><li>✅ 在你的裝置上安裝 Clawdbot</li><li>✅ 設定 AI 模型認證（Anthropic / OpenAI / 其他提供商）</li><li>✅ 啟動 Gateway 背景程序</li><li>✅ 透過 WebChat 或設定的頻道傳送第一條訊息</li></ul><p><strong>適合人群</strong>：所有使用者，必讀教學</p><p><strong>預計時間</strong>：15-20 分鐘</p><p><strong>主要內容</strong>：</p><ul><li>使用 npm/pnpm/bun 安裝 Clawdbot</li><li>執行 onboarding 引導完成基礎設定</li><li>啟動 Gateway 並驗證狀態</li><li>透過 CLI 或頻道傳送測試訊息</li></ul><p><strong>前置條件</strong>：無</p><hr><h3 id="_2-引導式設定" tabindex="-1"><a href="./onboarding-wizard/">2. 引導式設定</a> <a class="header-anchor" href="#_2-引導式設定" aria-label="Permalink to &quot;[2. 引導式設定](./onboarding-wizard/)&quot;">​</a></h3><p><strong>學完你能做什麼</strong>：</p><ul><li>✅ 使用互動式引導完成完整設定</li><li>✅ 理解 QuickStart 和 Manual 兩種模式的區別</li><li>✅ 設定 Gateway 網路、認證和 Tailscale</li><li>✅ 設定 AI 模型提供商（setup-token 和 API Key）</li><li>✅ 啟用通訊頻道（WhatsApp、Telegram 等）</li><li>✅ 安裝和管理技能包</li></ul><p><strong>適合人群</strong>：想要精細設定的使用者，了解進階選項</p><p><strong>預計時間</strong>：20-30 分鐘</p><p><strong>主要內容</strong>：</p><ul><li>QuickStart vs Manual 模式選擇</li><li>Gateway 網路設定（連接埠、綁定、認證）</li><li>AI 模型認證方式（setup-token 推薦）</li><li>通訊頻道設定流程</li><li>技能系統介紹</li></ul><p><strong>前置條件</strong>：<a href="./getting-started/">快速開始</a></p><hr><h3 id="_3-啟動-gateway-⭐-核心教學" tabindex="-1"><a href="./gateway-startup/">3. 啟動 Gateway</a> ⭐ 核心教學 <a class="header-anchor" href="#_3-啟動-gateway-⭐-核心教學" aria-label="Permalink to &quot;[3. 啟動 Gateway](./gateway-startup/) ⭐ 核心教學&quot;">​</a></h3><p><strong>學完你能做什麼</strong>：</p><ul><li>✅ 使用命令列啟動 Gateway 前台程序</li><li>✅ 設定 Gateway 為背景背景程序（macOS LaunchAgent / Linux systemd / Windows Scheduled Task）</li><li>✅ 理解不同綁定模式（loopback / LAN / Tailnet）和認證方式</li><li>✅ 在開發模式和生產模式之間切換</li><li>✅ 使用 <code>--force</code> 強制釋放被佔用的連接埠</li></ul><p><strong>適合人群</strong>：所有使用者，必讀教學</p><p><strong>預計時間</strong>：15-20 分鐘</p><p><strong>主要內容</strong>：</p><ul><li>前台模式 vs 背景程序模式</li><li>綁定模式選擇（loopback / LAN / Tailnet / Auto）</li><li>認證方式設定（Token / Password / Tailscale Identity）</li><li>開發模式（<code>--dev</code>）和生產模式</li><li>服務管理命令（install / start / stop / restart）</li><li>連接埠衝突處理（<code>--force</code>）</li></ul><p><strong>前置條件</strong>：<a href="./onboarding-wizard/">引導式設定</a></p><hr><h3 id="_4-傳送第一條訊息-⭐-核心教學" tabindex="-1"><a href="./first-message/">4. 傳送第一條訊息</a> ⭐ 核心教學 <a class="header-anchor" href="#_4-傳送第一條訊息-⭐-核心教學" aria-label="Permalink to &quot;[4. 傳送第一條訊息](./first-message/) ⭐ 核心教學&quot;">​</a></h3><p><strong>學完你能做什麼</strong>：</p><ul><li>✅ 透過 WebChat 介面傳送訊息</li><li>✅ 透過已設定頻道（WhatsApp / Telegram / Slack 等）與 AI 助手對話</li><li>✅ 理解訊息路由和回應流程</li><li>✅ 使用 AI 助手執行基本任務（查詢、摘要、程式碼生成等）</li></ul><p><strong>適合人群</strong>：所有使用者，必讀教學</p><p><strong>預計時間</strong>：10-15 分鐘</p><p><strong>主要內容</strong>：</p><ul><li>WebChat 介面使用</li><li>各頻道訊息傳送方式</li><li>訊息格式和回覆機制</li><li>常見任務範例（查詢資訊、生成程式碼、摘要文字）</li><li>除錯和故障排查</li></ul><p><strong>前置條件</strong>：<a href="./gateway-startup/">啟動 Gateway</a></p><hr><h3 id="_5-dm-配對與存取控制" tabindex="-1"><a href="./pairing-approval/">5. DM 配對與存取控制</a> <a class="header-anchor" href="#_5-dm-配對與存取控制" aria-label="Permalink to &quot;[5. DM 配對與存取控制](./pairing-approval/)&quot;">​</a></h3><p><strong>學完你能做什麼</strong>：</p><ul><li>✅ 了解預設的 DM 配對保護機制</li><li>✅ 核准或拒絕陌生傳送者的配對請求</li><li>✅ 設定白名單和黑名單</li><li>✅ 設定存取控制策略</li><li>✅ 理解配對模式和安全最佳實踐</li></ul><p><strong>適合人群</strong>：關注安全的使用者，推薦學習</p><p><strong>預計時間</strong>：10-15 分鐘</p><p><strong>主要內容</strong>：</p><ul><li>DM 配對機制原理</li><li>配對流程和使用者體驗</li><li>白名單和黑名單設定</li><li>存取控制策略設定</li><li>安全最佳實踐</li></ul><p><strong>前置條件</strong>：<a href="./first-message/">傳送第一條訊息</a></p><hr><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="q-我應該學習所有教學嗎" tabindex="-1">Q: 我應該學習所有教學嗎？ <a class="header-anchor" href="#q-我應該學習所有教學嗎" aria-label="Permalink to &quot;Q: 我應該學習所有教學嗎？&quot;">​</a></h3><p><strong>A</strong>: 不一定。如果你想快速上手，只需學習「快速開始」和「啟動 Gateway」兩個核心教學，然後就可以開始使用 Clawdbot 了。其他教學可以根據需要按需學習。</p><h3 id="q-跳過某些教學會有影響嗎" tabindex="-1">Q: 跳過某些教學會有影響嗎？ <a class="header-anchor" href="#q-跳過某些教學會有影響嗎" aria-label="Permalink to &quot;Q: 跳過某些教學會有影響嗎？&quot;">​</a></h3><p><strong>A</strong>: 不會。每個教學都是獨立的，但「快速開始」是基礎，包含了安裝和基本設定，建議首先學習。其他教學可以根據你的需求選擇性學習。</p><h3 id="q-我已經熟悉-ai-助手-可以跳過基礎教學嗎" tabindex="-1">Q: 我已經熟悉 AI 助手，可以跳過基礎教學嗎？ <a class="header-anchor" href="#q-我已經熟悉-ai-助手-可以跳過基礎教學嗎" aria-label="Permalink to &quot;Q: 我已經熟悉 AI 助手，可以跳過基礎教學嗎？&quot;">​</a></h3><p><strong>A</strong>: 可以。如果你已經熟悉類似的 AI 助手工具，可以跳過「快速開始」，直接學習「引導式設定」和「啟動 Gateway」來了解 Clawdbot 的特定設定和啟動方式。</p><h3 id="q-學習完本章節後-我可以做什麼" tabindex="-1">Q: 學習完本章節後，我可以做什麼？ <a class="header-anchor" href="#q-學習完本章節後-我可以做什麼" aria-label="Permalink to &quot;Q: 學習完本章節後，我可以做什麼？&quot;">​</a></h3><p><strong>A</strong>: 完成本章節後，你將擁有一個可以正常使用的 Clawdbot 系統，能夠：</p><ul><li>透過 WebChat 或多個頻道與 AI 助手對話</li><li>讓 AI 執行基本任務（查詢資訊、生成程式碼、摘要文字等）</li><li>使用 DM 配對機制保護安全</li><li>繼續學習進階功能（多頻道設定、工具系統、技能平台等）</li></ul><hr><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章節後，你可以繼續學習：</p><ul><li><strong><a href="./../../platforms/channels-overview/">多頻道系統概覽</a></strong>：了解 Clawdbot 支援的所有通訊頻道及其特點</li><li><strong><a href="./../../platforms/whatsapp/">WhatsApp 頻道</a></strong>：深入學習 WhatsApp 頻道的設定和使用</li><li><strong><a href="./../../platforms/telegram/">Telegram 頻道</a></strong>：深入學習 Telegram 頻道的設定和使用</li><li><strong><a href="./../../platforms/webchat/">WebChat 介面</a></strong>：了解內建的 WebChat 介面功能</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>根據你的使用需求，選擇對應的頻道進行深入學習。如果你主要使用某個頻道（如 WhatsApp 或 Telegram），可以優先學習該頻道的專門教學。</p></div>`,79)])])}const u=l(e,[["render",r]]);export{c as __pageData,u as default};
